export interface Record {
  id: number;
  name: string;
  category: string;
  value: number;
}

export type Stage = (records: Record[]) => Record[];

export type Filter = (record: Record) => boolean;

export function andFilter(...filters: Filter[]): Filter {
  return (record: Record) => filters.every((f) => f(record));
}

export function orFilter(...filters: Filter[]): Filter {
  return (record: Record) => filters.some((f) => f(record));
}

export function notFilter(filter: Filter): Filter {
  return (record: Record) => !filter(record);
}

export class Pipeline {
  private stages: Stage[] = [];
  private filters: Filter[] = [];

  addStage(stage: Stage): this {
    this.stages.push(stage);
    return this;
  }

  addFilter(filter: Filter): this {
    this.filters.push(filter);
    return this;
  }

  run(records: Record[]): Record[] {
    let result = [...records];
    if (this.filters.length > 0) {
      const combined = andFilter(...this.filters);
      result = result.filter(combined);
    }
    for (const stage of this.stages) {
      result = stage(result);
    }
    return result;
  }
}

export function doubleValues(records: Record[]): Record[] {
  return records.map((r) => ({ ...r, value: r.value * 2 }));
}

// --- handler.ts ---
export interface Item {
  id: string;
  name: string;
  status: "active" | "archived";
  createdAt: number;
  updatedAt: number;
}

export interface Request {
  method: "GET" | "POST" | "PUT" | "DELETE" | string;
  headers: Record<string, string>;
  params: Record<string, string>;
  body?: unknown;
}

export interface Response {
  status: number;
  body: unknown;
}

const store = new Map<string, Item>();

export function resetStore(): void {
  store.clear();
}

export function getStore(): Map<string, Item> {
  return store;
}

function ok(status: number, data: unknown): Response {
  return { status, body: { success: true, data } };
}

function fail(status: number, error: string): Response {
  return { status, body: { success: false, error } };
}

function isAuthorized(req: Request): boolean {
  return req.headers["authorization"] === "Bearer valid-token";
}

function checkAuth(req: Request): Response | null {
  if (!req.headers["authorization"]) {
    return fail(401, "Authorization required");
  }
  if (!isAuthorized(req)) {
    return fail(401, "Invalid token");
  }
  return null;
}

function getBodyRecord(req: Request): Record<string, unknown> | null {
  if (!req.body) return null;
  return req.body as Record<string, unknown>;
}

function hasStringField(
  data: Record<string, unknown>,
  field: string
): boolean {
  return typeof data[field] === "string" && (data[field] as string).length > 0;
}

function handleGet(req: Request): Response {
  const id = req.params["id"];
  if (!id) {
    return ok(200, Array.from(store.values()));
  }
  const item = store.get(id);
  return item ? ok(200, item) : fail(404, "Item not found");
}

function handlePost(req: Request): Response {
  const data = getBodyRecord(req);
  if (!data) {
    return fail(400, "Request body is required");
  }
  if (!hasStringField(data, "name")) {
    return fail(400, "Validation failed: name is required");
  }

  const id = data["id"] as string | undefined;
  if (id && store.has(id)) {
    return fail(409, "Item already exists");
  }

  const now = Date.now();
  const item: Item = {
    id: id || `item-${now}`,
    name: data["name"] as string,
    status: "active",
    createdAt: now,
    updatedAt: now,
  };
  store.set(item.id, item);
  return ok(201, item);
}

function applyUpdate(item: Item, data: Record<string, unknown>): Item {
  const updated: Item = { ...item, updatedAt: Date.now() };
  if (hasStringField(data, "name")) {
    updated.name = data["name"] as string;
  }
  if (data["status"] === "active" || data["status"] === "archived") {
    updated.status = data["status"] as "active" | "archived";
  }
  return updated;
}

function handlePut(req: Request): Response {
  const data = getBodyRecord(req);
  if (!data) {
    return fail(400, "Request body is required");
  }
  const id = req.params["id"];
  if (!id) {
    return fail(400, "Validation failed: id parameter is required");
  }

  const item = store.get(id);
  if (!item) {
    return fail(404, "Item not found");
  }

  const updated = applyUpdate(item, data);
  store.set(id, updated);
  return ok(200, updated);
}

function handleDelete(req: Request): Response {
  const id = req.params["id"];
  if (!id) {
    return fail(400, "Validation failed: id parameter is required");
  }
  if (!store.has(id)) {
    return fail(404, "Item not found");
  }
  store.delete(id);
  return ok(200, { deleted: id });
}

const methodHandlers: Record<string, (req: Request) => Response> = {
  GET: handleGet,
  POST: handlePost,
  PUT: handlePut,
  DELETE: handleDelete,
};

export function handleRequest(req: Request): Response {
  const authError = checkAuth(req);
  if (authError) {
    return authError;
  }

  const handler = methodHandlers[req.method];
  return handler ? handler(req) : fail(405, "Method not allowed");
}
